import{_ as i,o as s,c as a,ao as t}from"./chunks/framework.CASROgh4.js";const k=JSON.parse('{"title":"Confidence intervals","description":"","frontmatter":{},"headers":[],"relativePath":"confidence-intervals.md","filePath":"confidence-intervals.md","lastUpdated":null}'),n={name:"confidence-intervals.md"};function o(l,e,d,h,r,p){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="Confidence-intervals" tabindex="-1">Confidence intervals <a class="header-anchor" href="#Confidence-intervals" aria-label="Permalink to &quot;Confidence intervals {#Confidence-intervals}&quot;">​</a></h1><p>GLLVM.jl provides three complementary interval methods — <strong>Wald</strong>, <strong>profile likelihood</strong>, and <strong>parametric bootstrap</strong> — for both the Gaussian engine and every non-Gaussian family.</p><h2 id="Non-Gaussian-families-—-one-entry-point" tabindex="-1">Non-Gaussian families — one entry point <a class="header-anchor" href="#Non-Gaussian-families-—-one-entry-point" aria-label="Permalink to &quot;Non-Gaussian families — one entry point {#Non-Gaussian-families-—-one-entry-point}&quot;">​</a></h2><p>For a fitted non-Gaussian model, all three methods are reached through a single R-style call:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GLLVM, Distributions</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> fit_gllvm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Y; family </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Poisson</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), K </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">confint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, Y; method </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :wald</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)                          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># observed-information Wald</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">confint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, Y; method </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :profile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,  parm </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;beta[1]&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># profile-likelihood (LRT)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">confint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, Y; method </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :bootstrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, n_boot </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># parametric bootstrap</span></span></code></pre></div><p><code>Y</code> is the same response matrix you fitted — it is needed to reconstruct the marginal likelihood. The call returns a <code>NamedTuple</code> with <code>term</code>, <code>estimate</code>, <code>lower</code>, <code>upper</code>, and <code>method</code> (plus method-specific extras below).</p><p>Supported fits: the GLM families (<code>PoissonFit</code>, <code>BinomialFit</code>, <code>NBFit</code>, <code>BetaFit</code>, <code>GammaFit</code>) and the two-part families (<code>DeltaLogNormalFit</code>, <code>DeltaGammaFit</code>, <code>HurdlePoissonFit</code>, <code>HurdleNBFit</code>, <code>ZIPFit</code>, <code>ZINBFit</code>), and ordinal (<code>OrdinalFit</code>).</p><h3 id="Term-names" tabindex="-1">Term names <a class="header-anchor" href="#Term-names" aria-label="Permalink to &quot;Term names {#Term-names}&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Family group</th><th style="text-align:right;">Names</th></tr></thead><tbody><tr><td style="text-align:right;">GLM families</td><td style="text-align:right;"><code>beta[t]</code>, <code>Lambda[i,k]</code>, and a dispersion <code>r</code> / <code>phi</code> / <code>alpha</code></td></tr><tr><td style="text-align:right;">Two-part families</td><td style="text-align:right;"><code>betaz[t]</code> (occurrence / zero-inflation logits), <code>betac[t]</code> (value / count intercepts), <code>Lambda[i,k]</code>, and <code>sigma</code> / <code>alpha</code> / <code>r</code></td></tr><tr><td style="text-align:right;">Ordinal</td><td style="text-align:right;"><code>Lambda[i,k]</code>, <code>tau[c]</code> (cutpoints)</td></tr></tbody></table><p>Dispersion parameters are estimated on the log scale internally; their interval <strong>bounds are reported on the natural (positive) scale</strong>.</p><p><code>parm</code> subsets the terms: an exact name (<code>&quot;beta[1]&quot;</code>, <code>&quot;r&quot;</code>), a group (<code>&quot;beta&quot;</code>, <code>&quot;Lambda&quot;</code>, <code>&quot;betac&quot;</code>, <code>&quot;tau&quot;</code>), or a vector of these.</p><h2 id="The-three-methods" tabindex="-1">The three methods <a class="header-anchor" href="#The-three-methods" aria-label="Permalink to &quot;The three methods {#The-three-methods}&quot;">​</a></h2><h3 id="Wald-—-method-:wald" tabindex="-1">Wald — <code>method = :wald</code> <a class="header-anchor" href="#Wald-—-method-:wald" aria-label="Permalink to &quot;Wald — \`method = :wald\` {#Wald-—-method-:wald}&quot;">​</a></h3><p>The Hessian of the negative Laplace log-likelihood is formed by <strong>central finite differences</strong> at the MLE (the Laplace inner mode-finder is not forward-AD- friendly, matching how the fitters themselves are optimised), then inverted for the asymptotic covariance; <code>lower/upper = θ̂ ± z·SE</code>. Returns an extra <code>pd_hessian::Bool</code> flagging whether the observed information was positive definite. Cheapest method; assumes approximate normality on the working scale.</p><h3 id="Profile-likelihood-—-method-:profile" tabindex="-1">Profile likelihood — <code>method = :profile</code> <a class="header-anchor" href="#Profile-likelihood-—-method-:profile" aria-label="Permalink to &quot;Profile likelihood — \`method = :profile\` {#Profile-likelihood-—-method-:profile}&quot;">​</a></h3><p>Inverts the likelihood-ratio test: the deviance <code>D(c) = 2(ℓ̂ − ℓ_p(c))</code> is χ²₁ under <code>θ_i = c</code>, and the interval is <code>{c : D(c) ≤ qchisq(level, 1)}</code>. Each side is located by <strong>bracket-then-bisection</strong>, re-optimising the other parameters at every candidate. Better coverage than Wald when the likelihood is asymmetric. Returns a per-term <code>status</code> (<code>:profile</code> / <code>:partial</code> / <code>:failed</code>).</p><h3 id="Parametric-bootstrap-—-method-:bootstrap" tabindex="-1">Parametric bootstrap — <code>method = :bootstrap</code> <a class="header-anchor" href="#Parametric-bootstrap-—-method-:bootstrap" aria-label="Permalink to &quot;Parametric bootstrap — \`method = :bootstrap\` {#Parametric-bootstrap-—-method-:bootstrap}&quot;">​</a></h3><p>Simulates <code>n_boot</code> datasets from the fitted model, refits each, and takes percentile bounds. The gold standard for skewed or bounded parameters, at the cost of <code>n_boot</code> refits.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">confint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, Y; method </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :bootstrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, n_boot </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, parallel </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Set <code>parallel = true</code> to run replicates over <code>Threads.@threads</code>. <strong>Each replicate seeds its own RNG (<code>seed + b</code>)</strong>, so the result is independent of thread scheduling — multi-core and single-core give identical bounds. Returns an extra <code>n_converged::Int</code> (replicates whose refit failed or changed dimension are dropped). Start Julia with <code>julia -t auto</code> to use multiple threads.</p><h2 id="Gaussian-engine" tabindex="-1">Gaussian engine <a class="header-anchor" href="#Gaussian-engine" aria-label="Permalink to &quot;Gaussian engine {#Gaussian-engine}&quot;">​</a></h2><p>The Gaussian fit keeps its own dedicated functions (it has the richest parameter structure — <code>σ_eps</code>, between/within tiers, phylogenetic blocks):</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> fit_gaussian_gllvm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y; K </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">confint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit; y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> y)                       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Wald (observed information)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">profile_ci</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sigma_eps&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> y)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># profile likelihood</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bootstrap_ci</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit; y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> y, n_boot </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># parametric bootstrap</span></span></code></pre></div><p>and derived-quantity CIs (Σ_y entries, communality, correlation, phylogenetic signal H²) via <a href="/GLLVM.jl/previews/PR68/covariance-correlation"><code>confint_derived</code>-family helpers</a>.</p><p>See also: <a href="/GLLVM.jl/previews/PR68/response-families">Response families</a> · <a href="/GLLVM.jl/previews/PR68/working-with-a-fit">Working with a fit</a> · <a href="/GLLVM.jl/previews/PR68/api">Reference</a>.</p>`,25)])])}const g=i(n,[["render",o]]);export{k as __pageData,g as default};
